import json, sys
from datetime import datetime

data = json.load(sys.stdin)
feeds = data['feeds']

temp, hum, lux, soil = [], [], [], []
for f in feeds:
    if f.get('field1'): temp.append(float(f['field1']))
    if f.get('field2'): hum.append(float(f['field2']))
    if f.get('field3'): lux.append(float(f['field3']))
    if f.get('field4'): soil.append(float(f['field4']))

def stats(lst, name):
    if not lst: return f'{name}: No data'
    return f'{name}: avg={sum(lst)/len(lst):.1f}, min={min(lst):.1f}, max={max(lst):.1f}, count={len(lst)}'

print(stats(temp, 'temp'))
print(stats(hum, 'hum'))
print(stats(lux, 'lux'))
print(stats(soil, 'soil'))

# Store for later
import json
result = {
    'temp': {'avg': sum(temp)/len(temp), 'min': min(temp), 'max': max(temp), 'count': len(temp)} if temp else None,
    'hum': {'avg': sum(hum)/len(hum), 'min': min(hum), 'max': max(hum), 'count': len(hum)} if hum else None,
    'lux': {'avg': sum(lux)/len(lux), 'min': min(lux), 'max': max(lux), 'count': len(lux)} if lux else None,
    'soil': {'avg': sum(soil)/len(soil), 'min': min(soil), 'max': max(soil), 'count': len(soil)} if soil else None,
}
print('JSON_RESULT:' + json.dumps(result))
